{% extends '@PrestaShop/Admin/layout.html.twig' %}
{% set layoutHeaderToolbarBtn = {
  add: {
    href: path('admin_attribute_groups_create'),
    desc: 'Add new attribute'|trans({}, 'Admin.Catalog.Feature'),
    icon: 'add_circle_outline',
  }
}
%}

{% block content %}

  {% block attribute_group_showcase_card %}
    {% include '@PrestaShop/Admin/Sell/Catalog/AttributeGroup/Blocks/showcase_card.html.twig' %}
  {% endblock %}

  {% block attributes_listing %}
    {% include '@PrestaShop/Admin/Common/Grid/grid_panel.html.twig' with {'grid': attributeGroupGrid} %}
  {% endblock %}
{% endblock %}

{% block javascripts %}
  {{ parent() }}

  <script src=\"{{ asset('themes/default/js/bundle/pagination.js') }}\"></script>
  <script src=\"{{ asset('themes/new-theme/public/attribute_group.bundle.js') }}\"></script>
{% endblock %}
